#!/usr/bin/env python3
"""TASK-5: Create config.rs (SweepConfig) and job_script.rs (generate_job_script)"""
import base64, sys
from pathlib import Path

CONTENT = base64.b64decode("").decode()
TARGET = "examples/hubbard_u_sweep_slurm/src/config.rs"
TASK_ID = "TASK-5"

target_path = Path(TARGET)
target_path.parent.mkdir(parents=True, exist_ok=True)
target_path.write_text(CONTENT)

if not target_path.exists():
    print(f"FAILED {TASK_ID}: file not created at {TARGET}", file=sys.stderr)
    sys.exit(1)

print(f"OK {TASK_ID}: created {TARGET}")
